import fs from"fs";function isIterable(r){return Symbol.iterator in r}function transformFile(r,n,t){return transformSource(r,{filename:n,line:1,column:1,offset:0,data:fs.readFileSync(n,"utf-8")},t)}function transformString(r,n,t){return transformSource(r,{filename:"inline",line:1,column:1,offset:0,data:n},t)}async function transformSource(r,n,t){const a={hasChain:()=>!0,chain:t??(r=>[r])},e=await r.call(a,n);return isIterable(e)?await Promise.all(Array.from(e)):[e]}export{transformFile,transformSource,transformString};